from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ConnectionError, RequestError
import os
import logging
from functools import wraps
import time
from datetime import datetime

app = Flask(__name__)

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

ELASTICSEARCH_HOST = os.getenv('ELASTICSEARCH_HOST', 'localhost:9200')
ELASTICSEARCH_USER = os.getenv('ELASTICSEARCH_USER', '')
ELASTICSEARCH_PASSWORD = os.getenv('ELASTICSEARCH_PASSWORD', '')
ELASTICSEARCH_INDEX = os.getenv('ELASTICSEARCH_INDEX', 'products')

if ELASTICSEARCH_USER and ELASTICSEARCH_PASSWORD:
    es = Elasticsearch(
        [ELASTICSEARCH_HOST],
        http_auth=(ELASTICSEARCH_USER, ELASTICSEARCH_PASSWORD),
        max_retries=3,
        retry_on_timeout=True,
        timeout=30
    )
else:
    es = Elasticsearch(
        [ELASTICSEARCH_HOST],
        max_retries=3,
        retry_on_timeout=True,
        timeout=30
    )

def rate_limit(max_requests=1000, window=60):
    request_counts = {}
    
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            now = time.time()
            ip = request.remote_addr
            
            if ip not in request_counts:
                request_counts[ip] = []
            
            request_counts[ip] = [req_time for req_time in request_counts[ip] if now - req_time < window]
            
            if len(request_counts[ip]) >= max_requests:
                return jsonify({
                    'error': 'Rate limit exceeded',
                    'message': f'Maximum {max_requests} requests per {window} seconds'
                }), 429
            
            request_counts[ip].append(now)
            return f(*args, **kwargs)
        return wrapped
    return decorator

@app.route('/health', methods=['GET'])
def health_check():
    try:
        if es.ping():
            return jsonify({'status': 'healthy', 'elasticsearch': 'connected'}), 200
        else:
            return jsonify({'status': 'unhealthy', 'elasticsearch': 'disconnected'}), 503
    except Exception as e:
        return jsonify({'status': 'unhealthy', 'error': str(e)}), 503

@app.route('/api/search', methods=['GET'])
@rate_limit(max_requests=1000, window=60)
def search_products():
    start_time = time.time()
    
    query_param = request.args.get('q', '').strip()
    page = request.args.get('page', 1, type=int)
    page_size = request.args.get('size', 20, type=int)
    sort_by = request.args.get('sort', 'relevance')
    
    if not query_param:
        return jsonify({
            'error': 'Missing query parameter',
            'message': 'Please provide a search query using ?q=keyword'
        }), 400
    
    if page < 1:
        page = 1
    if page_size < 1 or page_size > 100:
        page_size = 20
    
    from_index = (page - 1) * page_size
    
    try:
        search_body = build_search_query(query_param, sort_by)
        
        response = es.search(
            index=ELASTICSEARCH_INDEX,
            body=search_body,
            from_=from_index,
            size=page_size,
            request_timeout=30
        )
        
        products = []
        for hit in response['hits']['hits']:
            product = hit['_source']
            product['id'] = hit['_id']
            product['score'] = hit['_score']
            products.append(product)
        
        total_hits = response['hits']['total']['value']
        total_pages = (total_hits + page_size - 1) // page_size
        
        elapsed_time = time.time() - start_time
        
        result = {
            'query': query_param,
            'total': total_hits,
            'page': page,
            'page_size': page_size,
            'total_pages': total_pages,
            'products': products,
            'took_ms': int(response['took']),
            'elapsed_ms': int(elapsed_time * 1000)
        }
        
        logger.info(f"Search query='{query_param}' returned {len(products)} results in {elapsed_time:.3f}s")
        
        return jsonify(result), 200
        
    except ConnectionError as e:
        logger.error(f"Elasticsearch connection error: {str(e)}")
        return jsonify({
            'error': 'Service unavailable',
            'message': 'Search service is temporarily unavailable'
        }), 503
        
    except RequestError as e:
        logger.error(f"Elasticsearch request error: {str(e)}")
        return jsonify({
            'error': 'Invalid search request',
            'message': 'Unable to process search query'
        }), 400
        
    except Exception as e:
        logger.error(f"Unexpected error during search: {str(e)}")
        return jsonify({
            'error': 'Internal server error',
            'message': 'An unexpected error occurred'
        }), 500

def build_search_query(query, sort_by):
    search_query = {
        'query': {
            'bool': {
                'should': [
                    {
                        'multi_match': {
                            'query': query,
                            'fields': [
                                'name^3',
                                'description^2',
                                'category',
                                'brand^2',
                                'tags'
                            ],
                            'type': 'best_fields',
                            'fuzziness': 'AUTO'
                        }
                    },
                    {
                        'match_phrase': {
                            'name': {
                                'query': query,
                                'boost': 5
                            }
                        }
                    }
                ],
                'minimum_should_match': 1,
                'filter': [
                    {'term': {'is_active': True}}
                ]
            }
        },
        'highlight': {
            'fields': {
                'name': {},
                'description': {}
            },
            'pre_tags': ['<em>'],
            'post_tags': ['</em>']
        }
    }
    
    if sort_by == 'price_asc':
        search_query['sort'] = [{'price': {'order': 'asc'}}]
    elif sort_by == 'price_desc':
        search_query['sort'] = [{'price': {'order': 'desc'}}]
    elif sort_by == 'newest':
        search_query['sort'] = [{'created_at': {'order': 'desc'}}]
    elif sort_by == 'popularity':
        search_query['sort'] = [{'sales_count': {'order': 'desc'}}]
    
    return search_query

